import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What are the three body types?", a: "The classic somatotypes are ectomorph, mesomorph, and endomorph, describing broad tendencies in build and fat or muscle distribution." },
  { q: "How do you determine your body type?", a: "This calculator uses height, weight, wrist, hip, BMI, and frame-size clues to estimate a likely body type." },
  { q: "Can your body type change?", a: "Your bone structure is mostly stable, but body composition, muscle, and fat distribution can change with training, diet, and time." },
  { q: "How should an endomorph diet and train?", a: "Many endomorphs benefit from strength training, regular cardio, high protein, fiber-rich foods, and controlled calorie intake." },
  { q: "What is body frame size?", a: "Body frame size estimates skeletal build, often using wrist circumference relative to height." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function BodyTypeCalculator() {
  const [gender, setGender] = useState("Male");
  const [height, setHeight] = useState(70);
  const [weight, setWeight] = useState(175);
  const [wrist, setWrist] = useState(7);
  const [hip, setHip] = useState(40);
  const [waist, setWaist] = useState(34);
  const result = useMemo(() => {
    const bmi = weight / (height * height) * 703;
    const ratio = height / wrist;
    const frame = ratio > 10.4 ? "Small" : ratio < 9.6 ? "Large" : "Medium";
    const whr = waist / hip;
    const type = bmi < 20 && frame === "Small" ? "Ectomorph" : bmi > 26 || whr > (gender === "Male" ? 0.9 : 0.85) ? "Endomorph" : "Mesomorph";
    return { bmi, frame, whr, type };
  }, [gender, height, weight, wrist, hip, waist]);
  const rows = [["Ectomorph", "Naturally lean, narrow frame", "Often faster", "Calorie surplus and protein", "Progressive strength training"], ["Mesomorph", "Athletic, balanced frame", "Moderate", "Balanced macros", "Strength plus conditioning"], ["Endomorph", "Higher fat storage tendency", "Often slower", "Protein, fiber, calorie control", "Strength plus cardio"]];
  return (
    <>
      <SEOHead title="Free Body Type Calculator Online - Find Your Ectomorph Mesomorph or Endomorph Type | CalcHive" description="Free online body type calculator. Find out if you are an ectomorph, mesomorph or endomorph and get personalized diet and training recommendations instantly. 100% free, no signup required." canonical="/body-type-calculator" keywords="free body type calculator, ectomorph mesomorph endomorph calculator free, somatotype calculator free online, find my body type free, body frame size calculator free online" category="Health Calculators" breadcrumbName="Free Body Type Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Body Type Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate somatotype, frame size, and waist-to-hip ratio from body measurements.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (lb)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Wrist circumference (in)</label><input type="number" value={wrist} onChange={(e) => setWrist(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Waist circumference (in)</label><input type="number" value={waist} onChange={(e) => setWaist(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Hip circumference (in)</label><input type="number" value={hip} onChange={(e) => setHip(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated Body Type</p><p className="text-5xl sm:text-6xl font-black text-white">{result.type}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Frame size</p><p className="text-lg font-extrabold">{result.frame}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Waist-to-hip</p><p className="text-lg font-extrabold">{result.whr.toFixed(2)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">BMI</p><p className="text-lg font-extrabold">{result.bmi.toFixed(1)}</p></div></div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Body Type for Free</h2><p className="text-muted-foreground leading-relaxed">This educational estimate combines frame size, BMI, and waist-to-hip ratio to suggest a likely somatotype.</p><h2 className="text-2xl font-bold">Ectomorph vs Mesomorph vs Endomorph - What Is the Difference</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Body Type Characteristics and Recommendations</caption><thead className="bg-muted/60"><tr>{["Body Type", "Characteristics", "Metabolism", "Best Diet Approach", "Best Training Approach"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Somatotype Body Type Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/body-type-calculator" headingLevel="h3" /></main>
    </>
  );
}


